import{M as s}from"../shared/index.js";window.addEventListener("message",r=>{if(r.source!==window)return;const e=r.data;if(!(!e||typeof e.type!="string"))switch(e.type){case s.CLOAKFOX_ACTIVE:browser.runtime.sendMessage({type:s.CLOAKFOX_ACTIVE,domain:e.domain});break;case s.FINGERPRINT_ACCESS:browser.runtime.sendMessage({type:s.FINGERPRINT_ACCESS,category:e.category,api:e.api});break}});browser.runtime.onMessage.addListener(r=>{r.type===s.STATUS&&window.postMessage(r,"*")});
